import{_ as n,o as a,c as e,ak as p}from"./chunks/framework.DwHlt8HN.js";const h=JSON.parse('{"title":"自动化运维","description":"","frontmatter":{},"headers":[],"relativePath":"devops/automation/index.md","filePath":"devops/automation/index.md","lastUpdated":1774320699000}'),l={name:"devops/automation/index.md"};function r(t,s,i,o,b,c){return a(),e("div",null,[...s[0]||(s[0]=[p(`<h1 id="自动化运维" tabindex="-1">自动化运维 <a class="header-anchor" href="#自动化运维" aria-label="Permalink to “自动化运维”">​</a></h1><p>让机器做重复的事，让人做有创造力的事。</p><p>运维的终极目标，不是成为一个「熟练的命令行使用者」，而是把那些重复的、有规律的运维工作自动化，让自己的精力聚焦在更有价值的事情上——架构设计、故障分析、性能调优。</p><p>这篇文章系列覆盖三大核心领域：<strong>Ansible</strong> 自动化配置管理、<strong>Prometheus + Grafana</strong> 监控体系、以及<strong>日志系统</strong>（ELK/EFK/Loki）。从基础设施配置到应用监控，再到日志收集与分布式追踪，构建起完整的可观测性体系。</p><h2 id="模块速览" tabindex="-1">模块速览 <a class="header-anchor" href="#模块速览" aria-label="Permalink to “模块速览”">​</a></h2><p>自动化运维的核心是「测量 - 监控 - 告警 - 响应」的闭环。每个环节都有对应的工具和最佳实践。</p><table tabindex="0"><thead><tr><th>方向</th><th>篇数</th><th>核心目标</th></tr></thead><tbody><tr><td><a href="/devops/ansible/architecture">Ansible</a></td><td>4 篇</td><td>配置管理、Playbook、Roles、与 K8s 集成</td></tr><tr><td><a href="/devops/monitor/prometheus-data">Prometheus + Grafana</a></td><td>8 篇</td><td>指标体系、PromQL、服务发现、可视化仪表盘</td></tr><tr><td><a href="/devops/monitor/elk">日志系统</a></td><td>5 篇</td><td>ELK/EFK/Loki 架构对比、日志收集方案</td></tr><tr><td><a href="/devops/monitor/sre">SRE 与可观测性</a></td><td>2 篇</td><td>可观测性理论、链路追踪工具对比</td></tr></tbody></table><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to “学习路径建议”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第一阶段：监控基础（1 周）</span></span>
<span class="line"><span>→ Prometheus 数据模型与四大指标类型</span></span>
<span class="line"><span>→ 搭建 Prometheus + Grafana 监控栈</span></span>
<span class="line"><span>→ 编写 PromQL 查询语句</span></span>
<span class="line"><span>→ 服务发现配置（K8s、Consul）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二阶段：日志体系（1 周）</span></span>
<span class="line"><span>→ ELK Stack 架构与组件职责</span></span>
<span class="line"><span>→ EFK 方案：Fluentd/Fluent Bit 的选型</span></span>
<span class="line"><span>→ Loki 的设计理念与适用场景</span></span>
<span class="line"><span>→ 分布式日志追踪：ELK + Zipkin/Jaeger</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三阶段：配置管理（1 周）</span></span>
<span class="line"><span>→ Ansible Inventory 与 Playbook 基础</span></span>
<span class="line"><span>→ Ansible Roles 模块化实践</span></span>
<span class="line"><span>→ Ansible 与 Docker、Kubernetes 集成</span></span>
<span class="line"><span>→ 编写可复用的 Ansible Role</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第四阶段：可观测性闭环（1 周）</span></span>
<span class="line"><span>→ 指标、日志、链路三位一体的可观测性</span></span>
<span class="line"><span>→ 告警规则设计与 AlertManager 配置</span></span>
<span class="line"><span>→ SLO/SLA 定义与监控</span></span>
<span class="line"><span>→ 故障复盘与改进流程</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br></div></div><h2 id="可观测性的三个维度" tabindex="-1">可观测性的三个维度 <a class="header-anchor" href="#可观测性的三个维度" aria-label="Permalink to “可观测性的三个维度”">​</a></h2><p>现代运维讲究「可观测性」（Observability），它有三个核心支柱：</p><p><strong>指标（Metrics）</strong>：系统运行状态的数值度量。CPU 使用率、内存占用、请求延迟分位数——这些是 Prometheus 擅长的事情。指标的特点是：高度聚合、查询高效，适合告警和趋势分析。</p><p><strong>日志（Logs）</strong>：离散的事件记录。结构化日志（JSON）比文本日志更有价值，因为可以按字段检索和聚合。日志的特点是：信息量大、维度丰富，适合故障定位。</p><p><strong>链路追踪（Traces）</strong>：请求在分布式系统中的调用路径。一次 HTTP 请求从网关到服务 A，到服务 B，再到数据库，每一步的耗时和关系，都记录在 Trace 里。链路追踪的特点是：端到端关联，适合分析分布式系统的性能瓶颈。</p><p>三种数据各有侧重，组合起来才能构建完整的可观测性视图。</p><h2 id="面试的核心逻辑" tabindex="-1">面试的核心逻辑 <a class="header-anchor" href="#面试的核心逻辑" aria-label="Permalink to “面试的核心逻辑”">​</a></h2><p>自动化运维的面试，核心考察三个方面：</p><ol><li><strong>监控体系设计</strong>：你能说出 Prometheus 的数据模型吗？四大指标类型各自的应用场景是什么？如何设计告警规则避免告警疲劳？</li><li><strong>问题排查能力</strong>：系统变慢了，怎么定位是数据库、缓存还是应用本身的问题？日志和指标在排查过程中各自扮演什么角色？</li><li><strong>自动化意识</strong>：哪些运维工作应该优先自动化？为什么？Ansible 和 Kubernetes 的自动化思路有什么区别？</li></ol><blockquote><p>&quot;好的运维，不是人盯着机器跑，而是让机器自动报告问题。不懂得利用工具的运维，是在用体力换效率。&quot;</p></blockquote>`,19)])])}const m=n(l,[["render",r]]);export{h as __pageData,m as default};
